/// Result of video sharing operation
class VideoShareResult {
  const VideoShareResult({
    required this.success,
    this.error,
    this.wasCancelled = false,
  });

  final bool success;
  final String? error;
  final bool wasCancelled;
}

/// Result of video validation
class VideoValidationResult {
  const VideoValidationResult({
    required this.isValid,
    this.errorMessage,
  });

  final bool isValid;
  final String? errorMessage;
}

typedef SharedVideoCallback = ({
  Future<VideoShareResult> Function({
    required Ball ball,
    required double fileSize,
    required double videoDuration,
    required String extractedVideoUrl,
  }) shareVideo,
  void Function() cancel,
});

/// Hook function for sharing video with optional improved UI and cancellation support
SharedVideoCallback useSharedVideo() {
  final logger = FimberLog('useSharedVideo');
  final context = useContext();
  final ref = useWidgetRef();
  final unitType = ref.watch(appUnitProvider);

  // Cancellation support
  final cancelCompleter = useRef<Completer<void>?>(null);
  final isCancelled = useRef(false);

  // Progress notifier for UI
  final isDisposed = useRef(false);

  // Track disposal state when the hook is disposed
  useEffect(() {
    return () {
      isDisposed.value = true;
    };
  }, []);

  // Cancel function
  void cancel() {
    isCancelled.value = true;
    cancelCompleter.value?.complete();
    logger.d('Video sharing operation cancelled');
  }

  // Unified share function with optional progress dialog
  Future<VideoShareResult> shareVideo({
    required Ball ball,
    required double fileSize,
    required double videoDuration,
    required String extractedVideoUrl,
  }) async {
    // Reset cancellation state
    isCancelled.value = false;
    cancelCompleter.value = Completer<void>();
    final progressNotifier = ValueNotifier<double?>(null);

    String? downloadedVideoPath;
    String? tempInputPath;
    String? outputPath;
    dynamic dialogRoute;

    try {
      // Show progress dialog if requested
      if (context.mounted) {
        dialogRoute = showCancellableLoadingDialogWithProgress(
          context: context,
          title: context.l10n.resource_details_page__shared_video_title,
          message: context.l10n.resource_details_page__shared_video_message,
          progressNotifier: progressNotifier,
          onCancel: cancel,
        );
      }

      // Check if operation was cancelled before starting
      if (isCancelled.value) {
        return const VideoShareResult(success: false, wasCancelled: true);
      }

      // Setup temporary directory
      final tempDir = await getTemporaryDirectory();

      // Download video from S3 URL if it's a network URL
      if (extractedVideoUrl.startsWith('http://') ||
          extractedVideoUrl.startsWith('https://')) {
        logger.d('Downloading video from S3: $extractedVideoUrl');

        // Create a unique filename for the downloaded video
        final uri = Uri.parse(extractedVideoUrl);
        final originalFileName = uri.pathSegments.last;
        downloadedVideoPath =
            join(tempDir.path, 'downloaded_$originalFileName');

        // Download the video
        final dio = Dio();
        final cancelToken = CancelToken();

        // Set up cancellation
        cancelCompleter.value?.future.then((_) {
          cancelToken.cancel('User cancelled download');
        });

        try {
          await dio.download(
            extractedVideoUrl,
            downloadedVideoPath,
            cancelToken: cancelToken,
            onReceiveProgress: (received, total) {
              if (total != -1 && !isDisposed.value) {
                // Update progress for download phase (0-50%)
                progressNotifier.value = (received / total) * 0.5;
              }
            },
          );
        } on DioException catch (e) {
          if (e.type == DioExceptionType.cancel) {
            logger.d('Download cancelled by user');
            return const VideoShareResult(success: false, wasCancelled: true);
          }
          logger.e('Failed to download video from S3', ex: e);
          return VideoShareResult(
            success: false,
            error: 'Failed to download video: ${e.message}',
          );
        }

        logger.d('Video downloaded successfully to: $downloadedVideoPath');
      } else {
        // If it's already a local file path, use it directly
        downloadedVideoPath = extractedVideoUrl;
      }

      // Validate downloaded file exists
      final originalFile = File(downloadedVideoPath);
      if (!await originalFile.exists()) {
        final error =
            'Downloaded video file does not exist: $downloadedVideoPath';
        logger.e(error);
        return VideoShareResult(success: false, error: error);
      }

      if (context.mounted) {
        // Validate video duration and file size
        final validationResult = await _validateVideoConstraints(
          fileSize,
          videoDuration,
          context.l10n,
        );

        if (!validationResult.isValid) {
          return VideoShareResult(
            success: false,
            error: validationResult.errorMessage,
          );
        }
      }

      // Check cancellation before file operations
      if (isCancelled.value) {
        return const VideoShareResult(success: false, wasCancelled: true);
      }

      // Setup temporary directory and file paths
      final baseName = basenameWithoutExtension(downloadedVideoPath);
      final ext = extension(downloadedVideoPath).toLowerCase();

      tempInputPath = join(tempDir.path, '${baseName}_input$ext');
      outputPath = join(tempDir.path, '${baseName}_edited$ext')
          .replaceAll('.mov', '.mp4');

      // Check cancellation before file operations
      if (isCancelled.value) {
        return const VideoShareResult(success: false, wasCancelled: true);
      }

      // Copy original file to temporary directory
      await originalFile.copy(tempInputPath);

      // Clean up any existing output file
      await _deleteTempFileIfExists(outputPath);

      // Check cancellation before processing
      if (isCancelled.value) {
        return const VideoShareResult(success: false, wasCancelled: true);
      }

      // Check if context is still mounted
      if (!context.mounted) {
        return const VideoShareResult(
          success: false,
          error: 'Context no longer mounted',
        );
      }

      // Extract metrics for video processing
      final metrics = _extractMetricsFromBall(context.l10n, unitType, ball);

      // Process video with cancellation check and progress reporting
      await _processVideoWithCancellation(
        tempInputPath,
        outputPath,
        metrics,
        cancelCompleter.value!,
        onProgress: (progress) {
          // Update progress dialog if shown and notifier is valid
          if (!isDisposed.value) {
            // Video processing phase (50-100%)
            progressNotifier.value = 0.5 + (progress * 0.5);
          }
        },
      );

      // Check if operation was cancelled during processing
      if (isCancelled.value) {
        return const VideoShareResult(success: false, wasCancelled: true);
      }

      // Check if context is still mounted before sharing
      if (!context.mounted) {
        return const VideoShareResult(
          success: false,
          error: 'Context no longer mounted',
        );
      }

      // Share the processed video
      await SharePlus.instance.share(
        ShareParams(
          files: [XFile(outputPath)],
          subject: context.l10n.resource_details_page__share_subject,
        ),
      );

      return const VideoShareResult(success: true);
    } catch (e, stackTrace) {
      logger.e('Error during video sharing', ex: e, stacktrace: stackTrace);
      return VideoShareResult(
        success: false,
        error: e.toString(),
        wasCancelled: isCancelled.value,
      );
    } finally {
      // Remove progress dialog if it was shown
      if (dialogRoute != null && context.mounted) {
        await popCancellableLoadingDialog(
          context: context,
          route: dialogRoute,
        );
      }

      // Clean up temporary files including downloaded video
      final filesToCleanup = [tempInputPath, outputPath];

      // Only delete the downloaded video if it was downloaded from S3
      if (downloadedVideoPath != null &&
          downloadedVideoPath != extractedVideoUrl &&
          (extractedVideoUrl.startsWith('http://') ||
              extractedVideoUrl.startsWith('https://'))) {
        filesToCleanup.add(downloadedVideoPath);
      }

      await _cleanupTempFiles(filesToCleanup);
      cancelCompleter.value = null;
    }
  }

  return (shareVideo: shareVideo, cancel: cancel);
}

/// Process video with cancellation support and progress reporting
Future<void> _processVideoWithCancellation(
  String inputPath,
  String outputPath,
  Map<String, String> metrics,
  Completer<void> cancelCompleter, {
  void Function(double progress)? onProgress,
}) async {
  final processCompleter = Completer<void>();

  // Start video processing with progress callback
  final processFuture = KnowhereVideoEditorPlatform.instance.processVideo(
    inputPath: inputPath,
    outputPath: outputPath,
    metrics: metrics,
    onProgress: onProgress,
  );

  // Complete when processing is done
  processFuture.then((_) {
    if (!processCompleter.isCompleted) {
      processCompleter.complete();
    }
  }).catchError((error) {
    if (!processCompleter.isCompleted) {
      // Handle platform-specific cancellation errors gracefully
      if (error is PlatformException &&
          error.message?.contains('No active stream to cancel') == true) {
        // This is expected when cancellation occurs, treat as successful cancellation
        processCompleter.complete();
      } else {
        processCompleter.completeError(error);
      }
    }
  });

  // Set up cancellation listener
  cancelCompleter.future.then((_) {
    // Cancel the native video processing operation
    KnowhereVideoEditorPlatform.instance
        .cancelProcessVideo()
        .catchError((error) {
      // Log cancellation errors but don't fail the operation
      FimberLog('_processVideoWithCancellation')
          .w('Failed to cancel native video processing', ex: error);
    });

    // Complete the process completer if not already completed
    if (!processCompleter.isCompleted) {
      processCompleter.complete();
    }
  });

  // Wait for either completion or cancellation
  await processCompleter.future;
}

/// Extract metrics from ball data for video overlay
Map<String, String> _extractMetricsFromBall(
  L10n l10n,
  UnitType unitType,
  Ball ball,
) {
  // Define metrics in the desired display order
  late final Map<String, ValueAndUnit> metrics;

  if (ball.isHit == true) {
    metrics = <String, ValueAndUnit>{
      l10n.ball_details_page__exit_velocity:
          UnitConverter.formatVelocity(ball.exitVelocity, unitType),
      l10n.ball_details_page__angle: UnitConverter.formatAngle(ball.angle),
    };
  } else {
    metrics = <String, ValueAndUnit>{
      l10n.ball_details_page__initial_velocity:
          UnitConverter.formatVelocity(ball.initialVelocity, unitType),
      l10n.ball_details_page__horizontal_break:
          UnitConverter.formatBreak(ball.horizontalBreak, unitType),
      l10n.ball_details_page__vertical_break:
          UnitConverter.formatBreak(ball.verticalBreak, unitType),
      l10n.ball_details_page__gyro_degree:
          UnitConverter.formatGyroDegree(ball.gyroDegree),
      l10n.ball_details_page__spin_direction:
          UnitConverter.formatSpinDirection(ball.spinDirection),
      l10n.ball_details_page__efficiency:
          UnitConverter.formatEfficiency(ball.efficiency),
      l10n.ball_details_page__active_spin:
          UnitConverter.formatSpin(ball.activeSpin),
      l10n.ball_details_page__total_spin:
          UnitConverter.formatSpin(ball.totalSpin),
    };
  }

  return metrics
      .map((key, value) => MapEntry(key, '${value.value} ${value.unit}'));
}

/// Clean up temporary files safely
Future<void> _cleanupTempFiles(List<String?> filePaths) async {
  for (final path in filePaths) {
    if (path != null) {
      await _deleteTempFileIfExists(path);
    }
  }
}

/// Delete a temporary file if it exists
Future<void> _deleteTempFileIfExists(String path) async {
  try {
    final tempFile = File(path);
    if (await tempFile.exists()) {
      await tempFile.delete();
      FimberLog('_deleteTempFileIfExists').d('Deleted temp file: $path');
    }
  } catch (e) {
    FimberLog('_deleteTempFileIfExists')
        .w('Failed to delete temp file: $path', ex: e);
  }
}

/// Validate video constraints (duration and file size)
Future<VideoValidationResult> _validateVideoConstraints(
  double fileSize,
  double videoDuration,
  L10n l10n,
) async {
  const maxDurationSeconds = 20;
  const maxFileSizeBytes = 20 * 1024 * 1024; // 20MB

  try {
    // Check file size
    if (fileSize > maxFileSizeBytes) {
      return VideoValidationResult(
        isValid: false,
        errorMessage:
            l10n.resource_details_page__share_video_file_size_exceeded,
      );
    }

    // Check video duration
    if (videoDuration > maxDurationSeconds) {
      return VideoValidationResult(
        isValid: false,
        errorMessage: l10n.resource_details_page__share_video_duration_exceeded,
      );
    }

    return const VideoValidationResult(isValid: true);
  } catch (e) {
    FimberLog('_validateVideoConstraints')
        .e('Error validating video constraints', ex: e);
    return VideoValidationResult(
      isValid: false,
      errorMessage: 'Failed to validate video: ${e.toString()}',
    );
  }
}

